pub struct FrameAllocator {
    start: usize,
    end: usize,
    next: usize,
}

impl FrameAllocator {
    pub fn from_regions(regions: &[MemoryRegion]) -> Self {
        let usable = regions
            .iter()
            .find(|region| region.usable)
            .copied()
            .unwrap_or(MemoryRegion {
                start: 0,
                size: 0,
                usable: false,
            });
        Self {
            start: usable.start,
            end: usable.start + usable.size,
            next: usable.start,
        }
    }

    pub fn alloc_page(&mut self) -> Option<usize> {
        let page = self.next;
        let next = page.checked_add(PAGE_SIZE)?;
        if next > self.end {
            return None;
        }
        self.next = next;
        Some(page)
    }

    pub fn dealloc_page(&mut self, page: usize) {
        // For simple bump allocator, deallocation is a no-op for now.
        // Frames are tracked by OwnedFramesInner and freed via Arc drop.
        // The allocator cannot reclaim pages, but this is acceptable since
        // Owned storage frames are not reused until process termination.
        let _ = page;
    }

    pub fn used_bytes(&self) -> usize {
        self.next.saturating_sub(self.start)
    }
}

