        return status;
    }
    let built_kernel = PathBuf::from("target")
        .join(LOONGARCH_TARGET)
        .join("debug")
        .join(LOONGARCH_PACKAGE);
    match package_kernel_artifact(&built_kernel, "kernel-la") {
        Ok(path) => {
