struct Sv39PageTableBuilder {
    root_phys: usize,
    pages: Vec<alloc::boxed::Box<PageTablePage>>,
}

impl Sv39PageTableBuilder {
    fn new() -> Self {
        let mut root = alloc::boxed::Box::new(PageTablePage::new());
        let root_phys = (&mut *root as *mut PageTablePage) as usize;
        Self {
            root_phys,
            pages: vec![root],
